-- ==========================================
-- LOG DATA SEED SINKRONISASI REALISTIS (3 BULAN)
-- ==========================================
BEGIN;
TRUNCATE orders, mutasi_stok, customers RESTART IDENTITY CASCADE;

UPDATE customers c
SET 
  total_servis = COALESCE((SELECT COUNT(*) FROM orders o WHERE o.pelanggan_id = c.id), 0),
  terakhir_servis = (SELECT MAX(tanggal_masuk) FROM orders o WHERE o.pelanggan_id = c.id);

COMMIT;